// Split characters array into individual items for loop processing
const characters = $input.first().json.json.output.characters;

return characters.map(character => ({
  json: character
}));

// Build comprehensive image generation prompt for this character
const character = $input.first().json;
const visualStyle = $('Set Variables').first().json.json.output.visual_style;

const prompt = [
  `Professional portrait photograph of ${character.name}:`,
  `Appearance: ${character.description}.`,
  `Outfit: ${character.costume}.`,
  `Expression: ${character.personality.split(',')[0].trim()} demeanor.`,
  `Style: ${visualStyle.overall_aesthetic}.`,
  `Color palette: ${visualStyle.color_palette}.`,
  'High quality, detailed, professional lighting.',
  'Clean background, studio portrait style.',
  'Consistent character design for video production.'
].join(' ');

return [{
  json: {
    character_name: character.name,
    character_data: character,
    image_prompt: prompt,
    negative_prompt: 'blurry, low quality, distorted, multiple people, text, watermark'
  }
}];

