// Normalize Stability AI response into standard format
const item = $input.first().json;

// Check for error
if (item.error || (item.statusCode && item.statusCode >= 400)) {
  // All providers failed - return failed character with no image
  return [{
    json: {
      success: false,
      provider: 'none',
      image_url: null,
      task_id: null,
      character_name: $('Generate Image Prompt').first().json.character_name,
      character_data: $('Generate Image Prompt').first().json.character_data,
      error: 'All image generation providers failed'
    }
  }];
}

// Stability returns base64 artifacts
const artifacts = item.body?.artifacts || item.artifacts || [];
if (artifacts.length === 0) {
  return [{
    json: {
      success: false,
      provider: 'stability',
      image_url: null,
      task_id: null,
      character_name: $('Generate Image Prompt').first().json.character_name,
      character_data: $('Generate Image Prompt').first().json.character_data,
      error: 'Stability AI returned no artifacts'
    }
  }];
}

// Stability returns base64 images, we need to handle this differently
// Store the base64 data for S3 upload
return [{
  json: {
    success: true,
    provider: 'stability',
    image_base64: artifacts[0].base64,
    image_url: null,
    task_id: null,
    character_name: $('Generate Image Prompt').first().json.character_name,
    character_data: $('Generate Image Prompt').first().json.character_data
  }
}];

// Normalize FAL AI response into standard format
const item = $input.first().json;

const imageUrl = item.body?.images?.[0]?.url ||
                 item.images?.[0]?.url ||
                 null;

if (!imageUrl) {
  throw new Error('FAL AI returned no image URL');
}

return [{
  json: {
    success: true,
    provider: 'fal',
    image_url: imageUrl,
    task_id: null,
    character_name: $('Generate Image Prompt').first().json.character_name,
    character_data: $('Generate Image Prompt').first().json.character_data
  }
}];

// Upload the generated image to S3
// Downloads from source URL (or uses base64) and uploads to S3 path
const item = $input.first().json;
const s3BasePath = $('variable').first().json.s3_base_path;
const fileName = item.character_name.toLowerCase().replace(/\s+/g, '_');
const s3Key = `${s3BasePath}/${fileName}.png`;

if (!item.success) {
  // Skip upload for failed characters
  return [{
    json: {
      ...item,
      s3_url: null,
      s3_key: null
    }
  }];
}

let imageBuffer;

if (item.image_base64) {
  // Stability AI returns base64
  imageBuffer = Buffer.from(item.image_base64, 'base64');
} else if (item.image_url) {
  // KIE/FAL return URLs - download the image
  imageBuffer = await this.helpers.httpRequest({
    method: 'GET',
    url: item.image_url,
    encoding: 'arraybuffer'
  });
} else {
  return [{
    json: {
      ...item,
      s3_url: null,
      s3_key: null,
      error: 'No image data available for upload'
    }
  }];
}

// Upload to S3 via HTTP (pre-signed URL or direct)
// This uses the AWS S3 PutObject via the S3 credentials
const s3Bucket = $env.S3_BUCKET || 'vdo-gen';
const s3Region = $env.S3_REGION || 'us-east-1';
const s3Url = `https://${s3Bucket}.s3.${s3Region}.amazonaws.com/${s3Key}`;

try {
  await this.helpers.httpRequest({
    method: 'PUT',
    url: s3Url,
    headers: {
      'Content-Type': 'image/png'
    },
    body: imageBuffer,
    encoding: 'arraybuffer'
  });
} catch (uploadError) {
  // Retry up to 3 times
  let uploaded = false;
  for (let retry = 0; retry < 3; retry++) {
    try {
      await new Promise(resolve => setTimeout(resolve, 2000 * (retry + 1)));
      await this.helpers.httpRequest({
        method: 'PUT',
        url: s3Url,
        headers: {
          'Content-Type': 'image/png'
        },
        body: imageBuffer,
        encoding: 'arraybuffer'
      });
      uploaded = true;
      break;
    } catch (e) {
      // Continue retrying
    }
  }

  if (!uploaded) {
    return [{
      json: {
        ...item,
        s3_url: null,
        s3_key: s3Key,
        error: `S3 upload failed after 3 retries: ${uploadError.message}`
      }
    }];
  }
}

return [{
  json: {
    success: true,
    provider: item.provider,
    character_name: item.character_name,
    character_data: item.character_data,
    s3_url: s3Url,
    s3_key: s3Key,
    image_url: item.image_url
  }
}];

// Store the result and loop back for next character
const item = $input.first().json;

return [{
  json: {
    character_name: item.character_name,
    character_data: item.character_data,
    s3_url: item.s3_url || null,
    provider: item.provider || 'none',
    success: item.success !== false
  }
}];

// Aggregate all character results into final response
const allItems = $input.all();
const executionId = $('variable').first().json.execution_id;
$('When Executed by Another Workflow').first().json.output
const characters = allItems.map(item => ({
  name: item.json.character_name,
  description: item.json.character_data?.description || '',
  personality: item.json.character_data?.personality || '',
  costume: item.json.character_data?.costume || '',
  image_url: item.json.s3_url || null,
  provider: item.json.provider || 'none',
  generated_at: new Date().toISOString()
}));

const successful = characters.filter(c => c.image_url !== null).length;
const failed = characters.filter(c => c.image_url === null).length;

return [{
  json: {
    execution_id: executionId,
    characters: characters,
    total_characters: characters.length,
    generation_stats: {
      successful: successful,
      failed: failed
    }
  }
}];

